{
  "name": "LogiQueue Pro - Sistema de Gestão de Atendimento",
  "description": "Sistema inteligente de gestão de filas e separação de pedidos para logística e comércio, com chamadas por voz e painel em tempo real.",
  "requestFramePermissions": [
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Priority {
  NORMAL = 'NORMAL',
  PRIORITY = 'PRIORITÁRIO'
}

export enum ClientType {
  CLIENT = 'Cliente',
  REPRESENTATIVE = 'Representante',
  FREIGHT = 'Frete'
}

export enum VehicleType {
  PASSENGER = 'Veículo de Passeio',
  MOTORCYCLE = 'Motocicleta',
  PICKUP = 'Pickup',
  TRUCK = 'Caminhão',
  VAN = 'Van'
}

export enum TicketStatus {
  WAITING_SEPARATION = 'Aguardando separação',
  IN_SEPARATION = 'Separação em andamento',
  READY = 'Pronto para atendimento',
  CALLED = 'Chamado para atendimento',
  FINISHED = 'Atendimento finalizado'
}

export interface Ticket {
  id: string;
  password: string;
  customerName: string;
  priority: Priority;
  clientType: ClientType;
  vehicleType: VehicleType;
  orderNumber: string;
  arrivalTime: Date;
  status: TicketStatus;
  separationStartTime?: Date;
  separationEndTime?: Date;
  callTime?: Date;
}

export interface QueueState {
  tickets: Ticket[];
}

import React from 'react';

export const COLORS = {
  primary: '#1e40af', // Blue 800
  secondary: '#0f172a', // Slate 900
  accent: '#3b82f6', // Blue 500
  priority: '#ef4444', // Red 500
  normal: '#10b981', // Emerald 500
};

export const ICONS = {
  RECEPTION: <i className="fas fa-user-plus"></i>,
  SEPARATION: <i className="fas fa-boxes-packing"></i>,
  DASHBOARD: <i className="fas fa-tv"></i>,
  CLOCK: <i className="fas fa-clock"></i>,
  USER: <i className="fas fa-user"></i>,
  TRUCK: <i className="fas fa-truck"></i>,
};

import { GoogleGenAI, Modality } from "@google/genai";

const API_KEY = process.env.API_KEY || "";

// Custom simple base64 decoder as required
function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export const announceCustomerCall = async (customerName: string) => {
  if (!API_KEY) {
    console.warn("API Key missing. Voice call disabled.");
    return;
  }

  try {
    const ai = new GoogleGenAI({ apiKey: API_KEY });
    const prompt = `Fale de forma clara e profissional: Sr(a). ${customerName}, favor comparecer à área de atendimento.`;

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const audioBuffer = await decodeAudioData(
        decode(base64Audio),
        audioContext,
        24000,
        1
      );
      const source = audioContext.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(audioContext.destination);
      source.start();
    }
  } catch (error) {
    console.error("Error generating speech announcement:", error);
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { Ticket, Priority, ClientType, VehicleType, TicketStatus } from './types';
import ReceptionModule from './components/ReceptionModule';
import SeparationModule from './components/SeparationModule';
import CustomerDashboard from './components/CustomerDashboard';
import { ICONS } from './constants';

const App: React.FC = () => {
  const [activeModule, setActiveModule] = useState<'reception' | 'separation' | 'dashboard'>('reception');
  const [tickets, setTickets] = useState<Ticket[]>([]);

  // Load initial state or Mock data if needed
  useEffect(() => {
    const saved = localStorage.getItem('logi_queue_tickets');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        // Re-hydrate dates
        const hydrated = parsed.map((t: any) => ({
          ...t,
          arrivalTime: new Date(t.arrivalTime),
          separationStartTime: t.separationStartTime ? new Date(t.separationStartTime) : undefined,
          separationEndTime: t.separationEndTime ? new Date(t.separationEndTime) : undefined,
          callTime: t.callTime ? new Date(t.callTime) : undefined,
        }));
        setTickets(hydrated);
      } catch (e) {
        console.error("Failed to parse saved state", e);
      }
    }
  }, []);

  // Persist state
  useEffect(() => {
    localStorage.setItem('logi_queue_tickets', JSON.stringify(tickets));
  }, [tickets]);

  const addTicket = (ticket: Omit<Ticket, 'id' | 'password' | 'arrivalTime' | 'status'>) => {
    const newTicket: Ticket = {
      ...ticket,
      id: Math.random().toString(36).substr(2, 9),
      password: `${ticket.priority === Priority.PRIORITY ? 'P' : 'N'}-${(tickets.length + 1).toString().padStart(3, '0')}`,
      arrivalTime: new Date(),
      status: TicketStatus.WAITING_SEPARATION,
    };
    setTickets(prev => [...prev, newTicket]);
  };

  const updateTicketStatus = (id: string, newStatus: TicketStatus) => {
    setTickets(prev => prev.map(t => {
      if (t.id !== id) return t;

      const update: Partial<Ticket> = { status: newStatus };
      if (newStatus === TicketStatus.IN_SEPARATION) update.separationStartTime = new Date();
      if (newStatus === TicketStatus.READY) update.separationEndTime = new Date();
      if (newStatus === TicketStatus.CALLED) update.callTime = new Date();

      return { ...t, ...update };
    }));
  };

  const removeTicket = (id: string) => {
    setTickets(prev => prev.filter(t => t.id !== id));
  };

  return (
    <div className="min-h-screen flex flex-col">
      {/* Navigation Header */}
      <header className="bg-slate-900 text-white shadow-lg sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16 items-center">
            <div className="flex items-center gap-2">
              <div className="bg-blue-600 p-2 rounded-lg">
                <i className="fas fa-box-open text-xl"></i>
              </div>
              <h1 className="text-xl font-bold tracking-tight">LogiQueue <span className="text-blue-400">Pro</span></h1>
            </div>

            <nav className="hidden md:flex space-x-4">
              <button 
                onClick={() => setActiveModule('reception')}
                className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${activeModule === 'reception' ? 'bg-blue-600 text-white' : 'text-gray-300 hover:bg-slate-800'}`}
              >
                {ICONS.RECEPTION} <span className="ml-2">Recepção</span>
              </button>
              <button 
                onClick={() => setActiveModule('separation')}
                className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${activeModule === 'separation' ? 'bg-blue-600 text-white' : 'text-gray-300 hover:bg-slate-800'}`}
              >
                {ICONS.SEPARATION} <span className="ml-2">Operacional</span>
              </button>
              <button 
                onClick={() => setActiveModule('dashboard')}
                className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${activeModule === 'dashboard' ? 'bg-blue-600 text-white' : 'text-gray-300 hover:bg-slate-800'}`}
              >
                {ICONS.DASHBOARD} <span className="ml-2">Painel do Cliente</span>
              </button>
            </nav>

            <div className="md:hidden flex items-center">
               <select 
                value={activeModule}
                onChange={(e) => setActiveModule(e.target.value as any)}
                className="bg-slate-800 border-none rounded p-1 text-sm outline-none"
               >
                 <option value="reception">Recepção</option>
                 <option value="separation">Operacional</option>
                 <option value="dashboard">Painel</option>
               </select>
            </div>
          </div>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 max-w-7xl mx-auto w-full p-4 sm:p-6 lg:p-8">
        {activeModule === 'reception' && (
          <ReceptionModule onAddTicket={addTicket} tickets={tickets} />
        )}
        {activeModule === 'separation' && (
          <SeparationModule 
            tickets={tickets} 
            onUpdateStatus={updateTicketStatus} 
            onRemove={removeTicket} 
          />
        )}
        {activeModule === 'dashboard' && (
          <CustomerDashboard tickets={tickets} />
        )}
      </main>

      <footer className="bg-white border-t border-gray-200 py-4 px-6 text-center text-gray-500 text-sm">
        LogiQueue Pro © {new Date().getFullYear()} - Sistema de Gestão de Atendimento Logístico
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Priority, ClientType, VehicleType, Ticket, TicketStatus } from '../types';
import { ICONS } from '../constants';

interface ReceptionModuleProps {
  onAddTicket: (ticket: Omit<Ticket, 'id' | 'password' | 'arrivalTime' | 'status'>) => void;
  tickets: Ticket[];
}

const ReceptionModule: React.FC<ReceptionModuleProps> = ({ onAddTicket, tickets }) => {
  const [formData, setFormData] = useState({
    customerName: '',
    priority: Priority.NORMAL,
    clientType: ClientType.CLIENT,
    vehicleType: VehicleType.PASSENGER,
    orderNumber: '',
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.customerName || !formData.orderNumber) return;

    onAddTicket(formData);
    setFormData({
      customerName: '',
      priority: Priority.NORMAL,
      clientType: ClientType.CLIENT,
      vehicleType: VehicleType.PASSENGER,
      orderNumber: '',
    });
  };

  const recentTickets = [...tickets]
    .sort((a, b) => b.arrivalTime.getTime() - a.arrivalTime.getTime())
    .slice(0, 5);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 animate-fadeIn">
      {/* Registration Form */}
      <div className="lg:col-span-2 bg-white rounded-xl shadow-sm border border-gray-200 p-6">
        <div className="flex items-center gap-3 mb-6">
          <div className="bg-blue-100 text-blue-600 p-3 rounded-full">
            {ICONS.RECEPTION}
          </div>
          <div>
            <h2 className="text-xl font-bold">Novo Atendimento</h2>
            <p className="text-sm text-gray-500">Registre a chegada do cliente no sistema</p>
          </div>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="flex flex-col gap-1">
              <label className="text-sm font-semibold text-gray-700">Nome do Cliente *</label>
              <input 
                required
                type="text"
                placeholder="Ex: João Silva"
                className="p-3 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                value={formData.customerName}
                onChange={e => setFormData({...formData, customerName: e.target.value})}
              />
            </div>
            <div className="flex flex-col gap-1">
              <label className="text-sm font-semibold text-gray-700">Número do Pedido *</label>
              <input 
                required
                type="text"
                placeholder="Ex: 45091"
                className="p-3 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                value={formData.orderNumber}
                onChange={e => setFormData({...formData, orderNumber: e.target.value})}
              />
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="flex flex-col gap-1">
              <label className="text-sm font-semibold text-gray-700">Prioridade</label>
              <select 
                className="p-3 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                value={formData.priority}
                onChange={e => setFormData({...formData, priority: e.target.value as Priority})}
              >
                <option value={Priority.NORMAL}>Normal</option>
                <option value={Priority.PRIORITY}>Prioritário</option>
              </select>
            </div>
            <div className="flex flex-col gap-1">
              <label className="text-sm font-semibold text-gray-700">Tipo de Cliente</label>
              <select 
                className="p-3 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                value={formData.clientType}
                onChange={e => setFormData({...formData, clientType: e.target.value as ClientType})}
              >
                {Object.values(ClientType).map(type => (
                  <option key={type} value={type}>{type}</option>
                ))}
              </select>
            </div>
            <div className="flex flex-col gap-1">
              <label className="text-sm font-semibold text-gray-700">Tipo de Veículo</label>
              <select 
                className="p-3 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                value={formData.vehicleType}
                onChange={e => setFormData({...formData, vehicleType: e.target.value as VehicleType})}
              >
                {Object.values(VehicleType).map(v => (
                  <option key={v} value={v}>{v}</option>
                ))}
              </select>
            </div>
          </div>

          <button 
            type="submit"
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 rounded-lg shadow-md transition-all active:scale-95 flex items-center justify-center gap-2"
          >
            <i className="fas fa-plus"></i> GERAR SENHA E INICIAR ATENDIMENTO
          </button>
        </form>
      </div>

      {/* Side Summary */}
      <div className="flex flex-col gap-6">
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
          <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
            <i className="fas fa-history text-gray-400"></i> Últimos Cadastros
          </h3>
          <div className="space-y-4">
            {recentTickets.length === 0 ? (
              <p className="text-gray-400 text-sm italic">Nenhum atendimento hoje.</p>
            ) : (
              recentTickets.map(ticket => (
                <div key={ticket.id} className="flex items-center justify-between border-b pb-3 last:border-0">
                  <div>
                    <p className="font-semibold text-gray-800">{ticket.customerName}</p>
                    <p className="text-xs text-gray-500">{ticket.password} • Pedido: {ticket.orderNumber}</p>
                  </div>
                  <span className={`px-2 py-1 rounded text-[10px] font-bold uppercase ${ticket.priority === Priority.PRIORITY ? 'bg-red-100 text-red-600' : 'bg-green-100 text-green-600'}`}>
                    {ticket.priority}
                  </span>
                </div>
              ))
            )}
          </div>
        </div>

        <div className="bg-slate-900 text-white rounded-xl shadow-lg p-6 flex items-center justify-between">
          <div>
            <p className="text-blue-400 text-xs font-bold uppercase mb-1">Total Hoje</p>
            <p className="text-3xl font-bold">{tickets.length}</p>
          </div>
          <div className="text-4xl text-white/20">
            <i className="fas fa-users"></i>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ReceptionModule;

import React from 'react';
import { Ticket, TicketStatus, Priority } from '../types';
import { announceCustomerCall } from '../services/geminiService';

interface SeparationModuleProps {
  tickets: Ticket[];
  onUpdateStatus: (id: string, status: TicketStatus) => void;
  onRemove: (id: string) => void;
}

const SeparationModule: React.FC<SeparationModuleProps> = ({ tickets, onUpdateStatus, onRemove }) => {

  // Custom sorting: Priority first, then Arrival Time
  const sortTickets = (list: Ticket[]) => {
    return [...list].sort((a, b) => {
      if (a.priority !== b.priority) {
        return a.priority === Priority.PRIORITY ? -1 : 1;
      }
      return a.arrivalTime.getTime() - b.arrivalTime.getTime();
    });
  };

  const waitingSeparation = sortTickets(tickets.filter(t => t.status === TicketStatus.WAITING_SEPARATION));
  const inSeparation = sortTickets(tickets.filter(t => t.status === TicketStatus.IN_SEPARATION));
  const readyToCall = sortTickets(tickets.filter(t => t.status === TicketStatus.READY));
  const activeCalls = tickets.filter(t => t.status === TicketStatus.CALLED);

  const handleCall = async (ticket: Ticket) => {
    onUpdateStatus(ticket.id, TicketStatus.CALLED);
    await announceCustomerCall(ticket.customerName);
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">

        {/* Stage 1: Waiting & In Progress Separation */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
          <div className="bg-slate-50 border-b p-4 flex justify-between items-center">
            <h3 className="font-bold text-gray-800 flex items-center gap-2">
              <i className="fas fa-dolly text-blue-600"></i> Fila de Separação
            </h3>
            <span className="bg-blue-100 text-blue-700 text-xs px-2 py-1 rounded-full font-bold">
              {waitingSeparation.length + inSeparation.length} Pedidos
            </span>
          </div>

          <div className="p-4 space-y-4 max-h-[600px] overflow-y-auto">
            {/* In Separation */}
            {inSeparation.map(ticket => (
              <div key={ticket.id} className="border-2 border-amber-200 bg-amber-50 rounded-lg p-4 relative">
                <div className="absolute top-2 right-2 flex gap-2">
                   <span className="text-[10px] bg-amber-200 text-amber-800 px-2 py-0.5 rounded font-bold uppercase">Em Andamento</span>
                   {ticket.priority === Priority.PRIORITY && (
                      <span className="text-[10px] bg-red-600 text-white px-2 py-0.5 rounded font-bold uppercase">Prioridade</span>
                   )}
                </div>
                <h4 className="font-bold text-lg text-gray-800">{ticket.customerName}</h4>
                <div className="flex gap-4 text-xs text-gray-600 mb-4 mt-1">
                  <span><i className="fas fa-hashtag"></i> {ticket.orderNumber}</span>
                  <span><i className="fas fa-ticket"></i> {ticket.password}</span>
                  <span><i className="fas fa-truck"></i> {ticket.vehicleType}</span>
                </div>
                <button 
                  onClick={() => onUpdateStatus(ticket.id, TicketStatus.READY)}
                  className="w-full bg-green-600 hover:bg-green-700 text-white py-2 rounded font-bold transition-all"
                >
                  <i className="fas fa-check mr-2"></i> Finalizar Separação
                </button>
              </div>
            ))}

            {/* Waiting */}
            {waitingSeparation.map(ticket => (
              <div key={ticket.id} className="border border-gray-200 rounded-lg p-4 hover:border-blue-300 transition-colors">
                <div className="flex justify-between items-start mb-2">
                  <h4 className="font-bold text-gray-800">{ticket.customerName}</h4>
                  {ticket.priority === Priority.PRIORITY && (
                    <span className="text-[10px] bg-red-100 text-red-600 px-2 py-0.5 rounded font-bold uppercase">Prioritário</span>
                  )}
                </div>
                <div className="flex gap-4 text-xs text-gray-500 mb-4">
                   <span><i className="fas fa-hashtag"></i> {ticket.orderNumber}</span>
                   <span><i className="fas fa-clock"></i> {ticket.arrivalTime.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                </div>
                <button 
                  onClick={() => onUpdateStatus(ticket.id, TicketStatus.IN_SEPARATION)}
                  className="w-full border border-blue-600 text-blue-600 hover:bg-blue-50 py-2 rounded font-bold transition-all"
                >
                  <i className="fas fa-play mr-2"></i> Iniciar Separação
                </button>
              </div>
            ))}

            {waitingSeparation.length === 0 && inSeparation.length === 0 && (
              <div className="text-center py-12 text-gray-400 italic">
                Nenhum pedido aguardando separação.
              </div>
            )}
          </div>
        </div>

        {/* Stage 2: Ready for Call */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
          <div className="bg-slate-50 border-b p-4 flex justify-between items-center">
            <h3 className="font-bold text-gray-800 flex items-center gap-2">
              <i className="fas fa-bullhorn text-emerald-600"></i> Fila de Chamada
            </h3>
            <span className="bg-emerald-100 text-emerald-700 text-xs px-2 py-1 rounded-full font-bold">
              {readyToCall.length} Prontos
            </span>
          </div>

          <div className="p-4 space-y-4 max-h-[600px] overflow-y-auto">
            {readyToCall.map(ticket => (
              <div key={ticket.id} className="border border-emerald-200 bg-emerald-50 rounded-lg p-4">
                <div className="flex justify-between items-center mb-4">
                  <div>
                    <h4 className="font-bold text-lg text-gray-800">{ticket.customerName}</h4>
                    <p className="text-xs text-gray-500">{ticket.password} • Pedido: {ticket.orderNumber}</p>
                  </div>
                  <div className="text-right">
                    <span className={`text-[10px] px-2 py-1 rounded font-bold uppercase ${ticket.priority === Priority.PRIORITY ? 'bg-red-500 text-white' : 'bg-gray-200 text-gray-700'}`}>
                      {ticket.priority}
                    </span>
                  </div>
                </div>
                <button 
                  onClick={() => handleCall(ticket)}
                  className="w-full bg-blue-600 hover:bg-blue-700 text-white py-3 rounded-lg font-bold shadow-sm transition-all flex items-center justify-center gap-2"
                >
                  <i className="fas fa-microphone"></i> CHAMAR CLIENTE
                </button>
              </div>
            ))}

            {readyToCall.length === 0 && (
              <div className="text-center py-12 text-gray-400 italic">
                Nenhum pedido pronto para chamada.
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Called History / Management */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
        <div className="bg-slate-50 border-b p-4">
           <h3 className="font-bold text-gray-800">Gerenciamento de Atendimentos</h3>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-gray-50 border-b text-gray-600 font-medium">
              <tr>
                <th className="px-6 py-3">Senha/Pedido</th>
                <th className="px-6 py-3">Cliente</th>
                <th className="px-6 py-3">Chegada</th>
                <th className="px-6 py-3">Status Atual</th>
                <th className="px-6 py-3 text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {tickets.map(t => (
                <tr key={t.id} className="hover:bg-gray-50 transition-colors">
                  <td className="px-6 py-4">
                    <p className="font-bold text-gray-900">{t.password}</p>
                    <p className="text-xs text-gray-500">#{t.orderNumber}</p>
                  </td>
                  <td className="px-6 py-4">
                    <p className="font-medium">{t.customerName}</p>
                    <p className="text-[10px] text-gray-400 uppercase tracking-tighter">{t.priority}</p>
                  </td>
                  <td className="px-6 py-4 text-gray-500">
                    {t.arrivalTime.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                  </td>
                  <td className="px-6 py-4">
                    <span className={`px-2 py-1 rounded-full text-[10px] font-bold ${
                      t.status === TicketStatus.CALLED ? 'bg-blue-100 text-blue-700' :
                      t.status === TicketStatus.READY ? 'bg-emerald-100 text-emerald-700' :
                      t.status === TicketStatus.IN_SEPARATION ? 'bg-amber-100 text-amber-700' :
                      'bg-gray-100 text-gray-600'
                    }`}>
                      {t.status}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-right space-x-2">
                    {t.status === TicketStatus.CALLED && (
                      <button 
                        onClick={() => onUpdateStatus(t.id, TicketStatus.FINISHED)}
                        className="text-emerald-600 hover:text-emerald-800 p-2"
                        title="Finalizar"
                      >
                        <i className="fas fa-check-double"></i>
                      </button>
                    )}
                    <button 
                      onClick={() => removeTicketFromSystem(t.id)}
                      className="text-gray-400 hover:text-red-600 p-2"
                      title="Excluir"
                    >
                      <i className="fas fa-trash"></i>
                    </button>
                  </td>
                </tr>
              ))}
              {tickets.length === 0 && (
                <tr>
                  <td colSpan={5} className="px-6 py-8 text-center text-gray-400 italic">Sem registros ativos.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );

  function removeTicketFromSystem(id: string) {
    if (confirm("Deseja realmente remover este registro do sistema?")) {
      onRemove(id);
    }
  }
};

