import React, { useEffect, useState } from 'react';
import { Ticket, TicketStatus, Priority } from '../types';

interface CustomerDashboardProps {
  tickets: Ticket[];
}

const CustomerDashboard: React.FC<CustomerDashboardProps> = ({ tickets }) => {
  const [lastCalled, setLastCalled] = useState<Ticket | null>(null);

  // Track last called for big display
  useEffect(() => {
    const called = tickets
      .filter(t => t.status === TicketStatus.CALLED)
      .sort((a, b) => (b.callTime?.getTime() || 0) - (a.callTime?.getTime() || 0));

    if (called.length > 0 && (!lastCalled || called[0].id !== lastCalled.id)) {
      setLastCalled(called[0]);
    }
  }, [tickets, lastCalled]);

  const ready = tickets.filter(t => t.status === TicketStatus.READY);
  const inSeparation = tickets.filter(t => t.status === TicketStatus.IN_SEPARATION);
  const waiting = tickets.filter(t => t.status === TicketStatus.WAITING_SEPARATION);

  const getEstimatedWait = () => {
    // Basic math: Avg separation 5 mins per person in front
    const ahead = waiting.length + inSeparation.length;
    return ahead * 5;
  };

  return (
    <div className="flex flex-col gap-8 h-full animate-fadeIn">
      {/* Top Banner - Last Called */}
      <div className="bg-blue-800 text-white rounded-2xl shadow-2xl p-8 flex flex-col items-center justify-center text-center relative overflow-hidden border-4 border-blue-600">
