        <div className="absolute bottom-0 left-0 w-64 h-64 bg-white/5 rounded-full -ml-32 -mb-32"></div>

        <h2 className="text-xl font-bold text-blue-200 uppercase tracking-widest mb-4">Última Chamada</h2>
