            <p className="text-6xl md:text-8xl font-black mb-2 tracking-tighter">{lastCalled.customerName}</p>
            <p className="text-2xl font-bold bg-white/20 px-6 py-2 rounded-full inline-block">Senha: {lastCalled.password}</p>
