      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 flex-1">

        {/* Status Columns */}
        <div className="bg-white rounded-xl shadow-sm border p-6">
          <h3 className="text-2xl font-bold text-emerald-600 mb-6 flex items-center justify-between">
            <span>Pronto</span>
            <span className="text-sm bg-emerald-100 px-3 py-1 rounded-full">{ready.length}</span>
          </h3>
          <div className="space-y-3">
            {ready.map(t => (
              <div key={t.id} className="bg-emerald-50 border border-emerald-100 p-4 rounded-xl flex justify-between items-center animate-slideUp">
                <div>
                  <p className="font-bold text-lg text-emerald-900 leading-tight">{t.customerName}</p>
                  <p className="text-xs text-emerald-600">{t.password}</p>
