export type AppModule = 'reception' | 'separation' | 'dashboard' | 'reports';

import React, { useState, useEffect } from 'react';
import { Ticket, Priority, TicketStatus, AppModule } from './types';
import ReceptionModule from './components/ReceptionModule';
import SeparationModule from './components/SeparationModule';
import CustomerDashboard from './components/CustomerDashboard';
import ReportsModule from './components/ReportsModule';
import WelcomeScreen from './components/WelcomeScreen';
import { ICONS, COLORS } from './constants';

const App: React.FC = () => {
  const [sessionDate, setSessionDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [activeModule, setActiveModule] = useState<AppModule | null>(null);
  const [tickets, setTickets] = useState<Ticket[]>([]);

  // Carregar dados baseados na data da sessão
  useEffect(() => {
    if (!sessionDate) return;
    const key = `normatel_tickets_${sessionDate}`;
    const saved = localStorage.getItem(key);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        const hydrated = parsed.map((t: any) => ({
          ...t,
          arrivalTime: new Date(t.arrivalTime),
          separationStartTime: t.separationStartTime ? new Date(t.separationStartTime) : undefined,
          separationEndTime: t.separationEndTime ? new Date(t.separationEndTime) : undefined,
          callTime: t.callTime ? new Date(t.callTime) : undefined,
          finishTime: t.finishTime ? new Date(t.finishTime) : undefined,
        }));
        setTickets(hydrated);
      } catch (e) {
        setTickets([]);
      }
    } else {
      setTickets([]);
    }
  }, [sessionDate]);

  // Salvar sempre que houver alteração
  useEffect(() => {
    if (!sessionDate || activeModule === 'reports') return;
    const key = `normatel_tickets_${sessionDate}`;
    localStorage.setItem(key, JSON.stringify(tickets));
  }, [tickets, sessionDate]);

  const addTicket = (ticket: Omit<Ticket, 'id' | 'password' | 'arrivalTime' | 'status'>) => {
    const isToday = sessionDate === new Date().toISOString().split('T')[0];
    if (!isToday && !confirm("Você está editando uma data retroativa. Deseja continuar?")) return;

    const newTicket: Ticket = {
      ...ticket,
      id: Math.random().toString(36).substr(2, 9),
      password: `${ticket.priority === Priority.PRIORITY ? 'P' : 'N'}-${(tickets.length + 1).toString().padStart(3, '0')}`,
      arrivalTime: new Date(),
      status: TicketStatus.WAITING_SEPARATION,
    };
    setTickets(prev => [...prev, newTicket]);
  };

  const updateTicketStatus = (id: string, newStatus: TicketStatus) => {
    setTickets(prev => prev.map(t => {
      if (t.id !== id) return t;
      const update: Partial<Ticket> = { status: newStatus };
      if (newStatus === TicketStatus.IN_SEPARATION) update.separationStartTime = new Date();
      if (newStatus === TicketStatus.READY) update.separationEndTime = new Date();
      if (newStatus === TicketStatus.CALLED) update.callTime = new Date();
      if (newStatus === TicketStatus.FINISHED) update.finishTime = new Date();
      return { ...t, ...update };
    }));
  };

  const removeTicket = (id: string) => {
    setTickets(prev => prev.filter(t => t.id !== id));
  };

  if (!activeModule) {
    return <WelcomeScreen 
      onSelect={(module, date) => {
        setActiveModule(module);
        setSessionDate(date);
      }} 
      initialDate={sessionDate}
    />;
  }

  return (
    <div className="min-h-screen flex flex-col bg-[#fcfcfc]">
      <header className="bg-[#1a1a1a] text-white shadow-xl sticky top-0 z-50 border-b-4 border-[#e67324]">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-20 items-center">
            <div className="flex items-center gap-4 cursor-pointer" onClick={() => setActiveModule(null)}>
              <div className="bg-[#e67324] p-2 rounded flex items-center justify-center w-12 h-12">
                <i className="fas fa-box text-2xl text-white"></i>
              </div>
              <div>
                <h1 className="text-xl font-bold tracking-tight leading-none">NORMATEL</h1>
                <p className="text-[10px] text-[#e67324] font-bold uppercase tracking-widest mt-1">Painel de Atendimento</p>
              </div>
            </div>

            <nav className="hidden lg:flex items-center space-x-2">
              <div className="flex bg-[#2a2a2a] rounded-lg p-1 mr-4 border border-[#3a3a3a]">
                <button onClick={() => setActiveModule('reception')} className={`px-4 py-2 rounded-md text-xs font-bold transition-all ${activeModule === 'reception' ? 'bg-[#e67324] text-white' : 'text-gray-400 hover:text-white'}`}>RECEPÇÃO</button>
                <button onClick={() => setActiveModule('separation')} className={`px-4 py-2 rounded-md text-xs font-bold transition-all ${activeModule === 'separation' ? 'bg-[#e67324] text-white' : 'text-gray-400 hover:text-white'}`}>OPERACIONAL</button>
                <button onClick={() => setActiveModule('dashboard')} className={`px-4 py-2 rounded-md text-xs font-bold transition-all ${activeModule === 'dashboard' ? 'bg-[#e67324] text-white' : 'text-gray-400 hover:text-white'}`}>PAINEL TV</button>
                <button onClick={() => setActiveModule('reports')} className={`px-4 py-2 rounded-md text-xs font-bold transition-all ${activeModule === 'reports' ? 'bg-[#e67324] text-white' : 'text-gray-400 hover:text-white'}`}>RELATÓRIOS</button>
              </div>
              <div className="flex items-center gap-2 px-3 py-2 bg-[#2a2a2a] rounded border border-[#3a3a3a] text-xs font-mono text-[#e67324]">
                {ICONS.CALENDAR} {new Date(sessionDate + "T12:00:00").toLocaleDateString('pt-BR')}
              </div>
            </nav>

            <button onClick={() => setActiveModule(null)} className="lg:hidden text-[#e67324] text-xl">
              <i className="fas fa-bars"></i>
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl mx-auto w-full p-4 sm:p-6 lg:p-8">
        {activeModule === 'reception' && <ReceptionModule onAddTicket={addTicket} tickets={tickets} />}
        {activeModule === 'separation' && <SeparationModule tickets={tickets} onUpdateStatus={updateTicketStatus} onRemove={removeTicket} />}
        {activeModule === 'dashboard' && <CustomerDashboard tickets={tickets} />}
        {activeModule === 'reports' && <ReportsModule />}
      </main>

      <footer className="bg-white border-t border-gray-200 py-4 px-6 text-center text-gray-400 text-[10px] uppercase font-bold tracking-widest">
        Painel de Atendimento Normatel • Versão 2.0 • {sessionDate}
      </footer>
    </div>
  );
};

export default App;

