            <h3 className="font-black text-white text-xs uppercase tracking-widest flex items-center gap-2">
              <i className="fas fa-boxes-packing text-[#e67324]"></i> FLUXO DE SEPARAÇÃO
            </h3>
            <span className="bg-[#e67324] text-white text-[10px] px-3 py-1 rounded-full font-black">
              {waiting.length + inProgress.length} ATIVOS
            </span>
          </div>

          <div className="p-6 space-y-6 max-h-[600px] overflow-y-auto">
            {inProgress.map(ticket => (
              <div key={ticket.id} className="bg-orange-50 border-2 border-[#e67324] rounded-2xl p-6 relative">
                <div className="flex justify-between items-start mb-4">
                   <h4 className="font-black text-2xl text-gray-900 tracking-tighter uppercase">{ticket.customerName}</h4>
                   <span className="text-[10px] bg-[#e67324] text-white px-3 py-1 rounded-lg font-black uppercase">EM SEPARAÇÃO</span>
                </div>
                <div className="flex gap-4 text-xs font-bold text-gray-500 mb-6">
                  <span className="bg-white px-2 py-1 rounded">#{ticket.orderNumber}</span>
                  <span className="bg-white px-2 py-1 rounded uppercase tracking-tighter">{ticket.password}</span>
                </div>
                <button onClick={() => onUpdateStatus(ticket.id, TicketStatus.READY)} className="w-full bg-[#1a1a1a] hover:bg-[#e67324] text-white py-4 rounded-xl font-black transition-all shadow-lg uppercase text-xs tracking-widest">
                  FINALIZAR SEPARAÇÃO
                </button>
