            ))}

            {waiting.map(ticket => (
              <div key={ticket.id} className="bg-gray-50 border border-gray-200 rounded-2xl p-6 hover:border-[#e67324] transition-all group">
                <div className="flex justify-between items-center mb-4">
                  <h4 className="font-black text-xl text-gray-800 tracking-tighter uppercase">{ticket.customerName}</h4>
                  {ticket.priority === Priority.PRIORITY && (
                    <span className="text-[10px] bg-red-600 text-white px-2 py-1 rounded font-black uppercase">PRIO</span>
                  )}
                </div>
                <button onClick={() => onUpdateStatus(ticket.id, TicketStatus.IN_SEPARATION)} className="w-full border-2 border-[#1a1a1a] text-[#1a1a1a] group-hover:bg-[#1a1a1a] group-hover:text-white py-3 rounded-xl font-black transition-all uppercase text-[10px] tracking-widest">
