interface LoginScreenProps {
  onLogin: (user: User) => void;
}

const LoginScreen: React.FC<LoginScreenProps> = ({ onLogin }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const usersRaw = localStorage.getItem('normatel_users');
    let users: User[] = [];

    if (usersRaw) {
      users = JSON.parse(usersRaw);
    } else {
      // Usuário padrão inicial se não houver nenhum
      const admin: User = { id: '1', username: 'admin', password: '123', role: 'admin', name: 'Administrador' };
      users = [admin];
      localStorage.setItem('normatel_users', JSON.stringify(users));
    }

    const user = users.find(u => u.username === username && u.password === password);

    if (user) {
      onLogin(user);
    } else {
      setError('Usuário ou senha inválidos.');
    }
  };

  return (
    <div className="min-h-screen bg-[#1a1a1a] flex items-center justify-center p-6 font-sans">
      <div className="max-w-md w-full bg-[#2a2a2a] rounded-3xl p-8 border border-[#3a3a3a] shadow-2xl">
        <div className="text-center mb-10">
          <div className="inline-block bg-[#e67324] p-4 rounded-2xl mb-6 shadow-xl">
            <i className="fas fa-lock text-3xl text-white"></i>
          </div>
          <h1 className="text-2xl font-black text-white tracking-tighter uppercase">
            Acesso Restrito
          </h1>
          <p className="text-gray-400 text-xs mt-2 uppercase font-bold tracking-widest">Painel Normatel</p>
        </div>

        <form onSubmit={handleLogin} className="space-y-6">
          <div>
            <label className="block text-[#e67324] text-[10px] font-black uppercase tracking-widest mb-2">Usuário</label>
            <div className="relative">
              <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500">
                <i className="fas fa-user"></i>
              </span>
              <input 
                type="text" 
                required
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                className="w-full bg-[#1a1a1a] border border-[#3a3a3a] text-white p-4 pl-12 rounded-xl focus:ring-2 focus:ring-[#e67324] outline-none font-bold"
                placeholder="Seu usuário"
              />
            </div>
          </div>

          <div>
            <label className="block text-[#e67324] text-[10px] font-black uppercase tracking-widest mb-2">Senha</label>
            <div className="relative">
              <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500">
                <i className="fas fa-key"></i>
              </span>
              <input 
                type="password" 
                required
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full bg-[#1a1a1a] border border-[#3a3a3a] text-white p-4 pl-12 rounded-xl focus:ring-2 focus:ring-[#e67324] outline-none font-bold"
                placeholder="••••••••"
              />
            </div>
          </div>

          {error && (
            <div className="bg-red-900/20 border border-red-500/50 p-3 rounded-lg text-red-400 text-xs font-bold text-center">
