                  <span className="bg-red-100 text-red-600 text-[10px] font-black px-2 py-1 rounded">PRIO</span>
                )}
              </div>
            ))}
            {recentTickets.length === 0 && <p className="text-center text-gray-400 italic text-sm py-4">Fila vazia</p>}
          </div>
        </div>
      </div>
    </div>
  );
};

