import { GoogleGenAI, Modality } from "@google/genai";

const API_KEY = process.env.API_KEY || "";

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  // Uso de DataView ou ajuste de offset para garantir alinhamento de 2 bytes (Int16)
  const dataInt16 = new Int16Array(data.buffer, data.byteOffset, data.byteLength / 2);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export const announceCustomerCall = async (customerName: string) => {
  if (!API_KEY) {
    console.warn("API Key não configurada. Ativando fallback silencioso.");
    return;
  }

  try {
    const ai = new GoogleGenAI({ apiKey: API_KEY });
    // Prompt mais natural para chamada de loja
    const prompt = `Atenção: Senhor ou Senhora ${customerName}, seu pedido está pronto. Favor comparecer ao balcão de atendimento. Repetindo: ${customerName}, ao atendimento por favor.`;

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      // Essencial para navegadores modernos que suspendem áudio
      if (audioContext.state === 'suspended') {
        await audioContext.resume();
      }

      const audioBuffer = await decodeAudioData(
        decode(base64Audio),
        audioContext,
        24000,
        1
      );
      const source = audioContext.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(audioContext.destination);
      source.start();

      console.log(`Anúncio de voz realizado para: ${customerName}`);
    }
  } catch (error) {
    console.error("Erro no serviço de voz Gemini:", error);
  }
};

