import { GoogleGenAI, Modality } from "@google/genai";

// Variável de controle para fila de reprodução de áudio
let nextStartTime = 0;
let globalAudioContext: AudioContext | null = null;

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export const announceCustomerCall = async (customerName: string) => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    // Texto alterado de "balcão" para "Atendimento externo"
    const prompt = `Atenção: ${customerName}, seu pedido está pronto. Favor comparecer ao Atendimento externo. Repetindo: ${customerName}, ao Atendimento externo por favor.`;

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      if (!globalAudioContext) {
        globalAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      if (globalAudioContext.state === 'suspended') {
        await globalAudioContext.resume();
      }

      const audioBuffer = await decodeAudioData(
        decode(base64Audio),
        globalAudioContext,
        24000,
        1
      );

      // Gerenciamento de tempo para fila (queuing)
      const currentTime = globalAudioContext.currentTime;
      nextStartTime = Math.max(nextStartTime, currentTime);

      const source = globalAudioContext.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(globalAudioContext.destination);

      // Agenda o início para o fim do áudio anterior
      source.start(nextStartTime);

      // Atualiza o cursor para o fim deste áudio
      nextStartTime += audioBuffer.duration;

      console.log(`Anúncio agendado para: ${customerName}`);
    }
  } catch (error) {
    console.error("Erro no serviço de voz Gemini:", error);
  }
};

import React from 'react';
import { Ticket, TicketStatus, Priority } from '../types';

interface SeparationModuleProps {
  tickets: Ticket[];
  onUpdateStatus: (id: string, status: TicketStatus) => void;
  onRemove: (id: string) => void;
}

const SeparationModule: React.FC<SeparationModuleProps> = ({ tickets, onUpdateStatus, onRemove }) => {
  const sortTickets = (list: Ticket[]) => {
    return [...list].sort((a, b) => {
      if (a.priority !== b.priority) return a.priority === Priority.PRIORITY ? -1 : 1;
      return new Date(a.arrivalTime).getTime() - new Date(b.arrivalTime).getTime();
    });
  };

  const waiting = sortTickets(tickets.filter(t => t.status === TicketStatus.WAITING_SEPARATION));
  const inProgress = sortTickets(tickets.filter(t => t.status === TicketStatus.IN_SEPARATION));
  const ready = sortTickets(tickets.filter(t => t.status === TicketStatus.READY));
  const called = sortTickets(tickets.filter(t => t.status === TicketStatus.CALLED));

  const handleCall = (ticket: Ticket) => {
    // Apenas atualiza o status. O Painel TV (CustomerDashboard) detectará a mudança e falará.
    onUpdateStatus(ticket.id, TicketStatus.CALLED);
